/* static: ডিফল্ট, স্বাভাবিক প্রবাহে থাকে */
.box1 { position: static; }

/* relative: নিজের আগের জায়গা থেকে সরে, কিন্তু জায়গা ধরে রাখে */
.box2 { position: relative; top: 10px; left: 20px; }

/* absolute: নিকটতম positioned (relative/absolute) প্যারেন্টের সাপেক্ষে */
.box3 { position: absolute; top: 0; right: 0; }

/* fixed: স্ক্রল করলেও স্ক্রিনের একই জায়গায় থাকে */
.box4 { position: fixed; bottom: 20px; right: 20px; }

/* sticky: স্বাভাবিক প্রবাহে থাকে, কিন্তু স্ক্রল করলে একটা পয়েন্টে আটকে যায় */
.navbar { position: sticky; top: 0; }
